import { Component } from "./component.js";
import { Delimiters } from "../../utils/enum.js";
import { HL7FatalError } from "../../utils/exception.js";
import { ValueNode } from "./valueNode.js";
/** @internal */
export class FieldRepetition extends ValueNode {
    /** @internal */
    constructor(parent, key, text) {
        super(parent, key, text, Delimiters.Component);
    }
    /** @internal */
    read(path) {
        const component = this.children[parseInt(path.shift()) - 1];
        return path.length > 0 ? component.read(path) : component;
    }
    /** @internal */
    writeCore(path, value) {
        return this.writeAtIndex(path, value, parseInt(path.shift()) - 1);
    }
    /** @internal */
    pathCore() {
        if (this.parent == null) {
            throw new HL7FatalError("this.parent must not be null.");
        }
        return this.parent.path;
    }
    /** @internal */
    createChild(text, index) {
        return new Component(this, (index + 1).toString(), text);
    }
}
